Here are some simple examples of code using some of the libraries mentioned to capture keystrokes:

**Example 1: Using SDL (Simple DirectMedia Layer)**

SDL is a cross-platform library that provides a set of functions for capturing keyboard and mouse input. Here's an example of how to use SDL to capture keystrokes:
```c
#include <SDL2/SDL.h>

int main(int argc, char* argv[]) {
    // Initialize SDL
    if (SDL_Init(SDL_INIT_VIDEO) < 0) {
        SDL_LogError(SDL_LOG_CATEGORY_APPLICATION, "Failed to initialize SDL: %s", SDL_GetError());
        return 1;
    }

    // Create a window
    SDL_Window* window = SDL_CreateWindow("Keystroke Capture", SDL_WINDOWPOS_CENTERED, SDL_WINDOWPOS_CENTERED, 640, 480, SDL_WINDOW_SHOWN);
    if (!window) {
        SDL_LogError(SDL_LOG_CATEGORY_APPLICATION, "Failed to create window: %s", SDL_GetError());
        SDL_Quit();
        return 1;
    }

    // Create a renderer
    SDL_Renderer* renderer = SDL_CreateRenderer(window, -1, SDL_RENDERER_ACCELERATED);
    if (!renderer) {
        SDL_LogError(SDL_LOG_CATEGORY_APPLICATION, "Failed to create renderer: %s", SDL_GetError());
        SDL_DestroyWindow(window);
        SDL_Quit();
        return 1;
    }

    // Set up event handling
    SDL_Event event;
    bool running = true;
    while (running) {
        while (SDL_PollEvent(&event)) {
            if (event.type == SDL_QUIT) {
                running = false;
            } else if (event.type == SDL_KEYDOWN) {
                SDL_Log("Keystroke: %s", SDL_GetKeyName(event.key.keysym.sym));
            }
        }

        // Update the renderer
        SDL_RenderClear(renderer);
        SDL_RenderPresent(renderer);

        // Cap the frame rate
        SDL_Delay(1000 / 60);
    }

    // Clean up
    SDL_DestroyRenderer(renderer);
    SDL_DestroyWindow(window);
    SDL_Quit();

    return 0;
}
```
**Example 2: Using GLFW (Graphics Library Framework)**

GLFW is a cross-platform library that provides a set of functions for capturing keyboard and mouse input. Here's an example of how to use GLFW to capture keystrokes:
```c
#include <GLFW/glfw3.h>

int main() {
    // Initialize GLFW
    if (!glfwInit()) {
        return -1;
    }

    // Create a window
    GLFWwindow* window = glfwCreateWindow(640, 480, "Keystroke Capture", NULL, NULL);
    if (!window) {
        glfwTerminate();
        return -1;
    }

    // Set up event handling
    glfwSetKeyCallback(window, [](GLFWwindow* window, int key, int scancode, int action, int mods) {
        if (action == GLFW_PRESS) {
            printf("Keystroke: %s\n", glfwGetKeyName(key));
        }
    });

    // Main loop
    while (!glfwWindowShouldClose(window)) {
        // Update the window
        glfwSwapBuffers(window);
        glfwPollEvents();

        // Cap the frame rate
        glfwWaitEventsTimeout(1.0 / 60.0);
    }

    // Clean up
    glfwDestroyWindow(window);
    glfwTerminate();

    return 0;
}
```
**Example 3: Using JavaScript and the Event Listener API**

Here's an example of how to use the Event Listener API to capture keystrokes in a web browser:
```javascript
document.addEventListener("keydown", (event) => {
    console.log(`Keystroke: ${event.key}`);
});
```
Note that these examples are just a starting point, and you may need to modify them to suit your specific needs. Additionally, these examples are for demonstration purposes only and may not be suitable for production use.
